class Solution:
    def distanceTraveled(self, mainTank: int, additionalTank: int) -> int:
        main = mainTank
        additional = additionalTank
        distance = 0
        while main >= 5:
            main -= 5
            distance += 50
            if additional > 0:
                main += 1
                additional -= 1
        distance += main * 10
        return distance
